{
  "name": "Nutrition Assistance (SNAP)",
  "eligibility": {
    "age": 60,
    "income_limits": "For households with a member 60+ or disabled (Oct 1, 2025 - Sept 30, 2026): Gross income limit at 185% FPL - 1 person: $2,412/month; 2: $3,261; 3: $4,108; 4: $4,956; 5: $5,805; 6: $6,652; 7: $7,499; +$847 each additional. If over gross limit, qualify via Net Income test (must be below 100% FPL after deductions, e.g., ~$1,305/month individual, $1,763 couple per older data) and Asset test. Annual equivalents like $19,584 for one-person noted in legislative context[1][3][6].",
    "asset_limits": "No asset limit for most Arizona households. For elderly/disabled households failing Gross Income test, federal rules apply: $4,500 limit on countable resources (e.g., bank accounts). Exempt: home, vehicles, retirement savings, household goods, life insurance cash value (varies)[1][2][3][6].",
    "other_requirements": ["Household must live in Arizona", "U.S. citizen or qualified non-citizen", "No work requirements for households entirely elderly (60+) or disabled", "Net income test always applies for elderly/disabled", "Social Security, pensions, VA/disability count as income"]
  },
  "benefits": {
    "type": "financial",
    "value": "Monthly EBT card for groceries (including online at Amazon, Walmart, Aldi/Instacart). Up to $234/month for one-person household (2022 data); calculated as max allotment minus 30% of net income (e.g., $546 max for 2-person elderly household minus 30% net = $415 example). Exact amount varies by net income, deductions (medical, shelter)[1][4][5].",
    "varies_by": "household_size"
  },
  "application": {
    "methods": ["Online: www.arizonaselfhelp.org or DES portal", "Phone: 1-855-777-8590 (Family Assistance Administration)", "Mail/paper: Submit to Arizona Department of Economic Security", "In-person: Local DES/FAA offices"],
    "processing_time": "Not specified in sources; typically 30 days standard, expedited for urgent cases",
    "waitlist": null,
    "forms": ["Online/paper SNAP application via Arizona Self-Help"],
    "documents": ["Proof of income (Social Security awards, pay stubs, pensions)", "ID", "Proof of expenses (medical bills over $35/month, rent/utility bills)", "Proof of disability if claimed", "Household composition details"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Administered uniformly statewide by AZ DES/FAA, but local offices may have varying wait times or processing; no specific differences noted[1][4][6].",
    "offices_or_providers": ["Local Family Assistance Administration (FAA) offices via 1-855-777-8590"]
  },
  "official_source": "https://des.az.gov/services/basic-needs/food/nutrition-assistance (inferred from context; use Arizona Self-Help at www.arizonaselfhelp.org for screening)",
  "gotchas": ["Elderly/disabled over gross income (185% FPL) must pass stricter Net + Asset tests ($4,500 limit)", "Medical expenses >$35/month and shelter costs deductible to lower net income", "Entire household (food buyers/preparers) included even if not all elderly", "No impact on other benefits except FDPIR", "Vehicles/home exempt from assets", "Broadened AZ rules looser than federal—check current via screener", "2025 federal changes (e.g., work rules) may apply per One Big Beautiful Bill Act[1][2][3][4][5]"],
  "data_shape_notes": "Elderly/disabled have special path: gross income optional (185% FPL table by household size), fallback to net income + $4,500 assets; benefits scale by household size and net income deductions; statewide with DES central admin"
}

{
  "name": "Arizona State Health Insurance Assistance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits; open to all Medicare beneficiaries, their families, and caregivers, with support prioritized for those with limited incomes, under age 65 with disabilities, or dually eligible for Medicare and Medicaid[2][3][6]",
    "asset_limits": "No asset limits or tests apply[6]",
    "other_requirements": ["Must be a Medicare beneficiary, family member, or caregiver in Arizona[1][2][3][5][6]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one personalized health insurance counseling and assistance on Medicare benefits, coverage decisions, Medicare Advantage, Medigap, Part D, appeals, long-term care insurance, Medicaid eligibility, Medicare Savings Programs (MSP), Extra Help/Low Income Subsidy, fraud prevention via Senior Medicare Patrol (SMP), outreach presentations, and enrollment events; no fixed dollar amounts or hours, services provided via phone, in-person, or virtually as needed[1][2][3][4][5][6][7][8]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-432-4040[5][6]", "Website intake form: https://azship.org[6]", "Local in-person or phone appointments via regional providers (e.g., SEAGO in Bisbee for 4-county region[7], PCOA at 8467 E Broadway Blvd, Tucson, AZ 85710, (520) 790-7262[8])", "Mail or additional contacts via Arizona Department of Economic Security, Division of Aging and Adult Services, 1789 West Jefferson, Site Code MD6288, Phoenix, AZ 85007[1]"],
    "processing_time": "Not specified; counselors return calls or schedule appointments promptly after contact[5][6][7]",
    "waitlist": null,
    "forms": ["Online intake form on azship.org (no specific form name/number listed)[6]"],
    "documents": ["No specific documents required for initial counseling; may need Medicare card, income details, or insurance documents for assistance with applications like MSP or Extra Help[2][4][6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide to Arizona Medicare beneficiaries[1][5]",
    "regional_variations": "Delivered through a network of local providers and Area Agencies on Aging (e.g., SEAGO for southeast counties, PCOA in Pima/Tucson area), with locally focused counseling on regional Medicare options, but core services consistent[4][6][7][8]",
    "offices_or_providers": ["Arizona Department of Economic Security (state office, Phoenix)[1]", "azship.org network[6]", "SEAGO (Bisbee, 4-county region)[7]", "PCOA (Tucson)[8]"]
  },
  "official_source": "https://azship.org",
  "gotchas": ["Not a direct financial aid or healthcare provider program—offers counseling only, not payment for services; people may miss that it helps apply for other programs like MSP (up to $8,400/year savings for individuals) or Extra Help; services rely on local availability of counselors/volunteers, so response times may vary; assumes Medicare enrollment[2][3][4][6]", "Even if income is near limits for related programs, SHIP assists with applications worth pursuing[6]"],
  "data_shape_notes": "no income/asset test; counseling-only service via statewide local network; prioritizes low-income/disabled/dual-eligible but open to all Medicare beneficiaries; integrates SMP for fraud prevention[2][3][6]"
}

{
  "name": "Arizona Senior Legal Helpline",
  "eligibility": {
    "age": 60,
    "income_limits": "No strict income limits; priority given to those with greatest economic and social need per federal regulations. Low-income individuals prioritized, but not explicitly defined by dollar amounts[2][4].",
    "asset_limits": "No asset limits mentioned.",
    "other_requirements": ["Must live in Maricopa County[2][4]", "Civil legal issues (excludes housing matters)[4]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free legal services for civil issues including wills/estate planning, powers of attorney/living wills, probate, bankruptcy, collection/consumer finances, Social Security/SSI benefits, veteran benefits. Referrals for cases outside expertise or not meeting low-income criteria[2][4].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: 602-252-6710 (Thursdays 10:00 a.m. to 1:00 p.m.)[2]", "Online: New Request for Service form at asclp.org[2]", "In-person: 2720 East Thomas Road, Phoenix, AZ 85016[4]"],
    "processing_time": "Not specified.",
    "waitlist": null,
    "forms": ["New Request for Service form (online)[2]"],
    "documents": ["Not specified; intake determines eligibility based on age, location, and need."]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Maricopa County only[2][4]",
    "regional_variations": "Limited to Maricopa County; other regions have separate legal aid like AZ Law Help (Apache, Gila, Navajo Counties: 1-866-637-5341), Volunteer Lawyer Program (Pima, Pinal, etc.: 1-800-640-9465), Elder Law Hotline (Maricopa: 1-800-231-5441)[3][5][6]",
    "offices_or_providers": ["2720 East Thomas Road, Phoenix, AZ 85016[2][4]"]
  },
  "official_source": "https://asclp.org",
  "gotchas": ["Restricted to Maricopa County residents only—families outside this area need alternative programs[2][4]", "No income guidelines but priority for greatest need; may not serve all applicants[2]", "Excludes housing matters; referrals for non-qualifying cases[4]", "Intake limited to specific phone hours[2]"],
  "data_shape_notes": "County-restricted to Maricopa; no income/asset test but priority-based; phone intake only Thursdays; separate from statewide legal aid networks."
}

{
  "name": "Arizona Long Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits; program is free and available to any resident of a qualifying long-term care facility regardless of financial status[3][5]",
    "asset_limits": "No asset limits or tests apply[3][5]",
    "other_requirements": ["Must be a resident of a qualifying long-term care facility such as nursing homes, assisted living facilities, adult foster care homes, hospice centers, or adult day care[3][5]", "Consent required from the resident (or their representative) for ombudsman to investigate complaints or act on their behalf[3][5]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Free and confidential advocacy services including: investigation of complaints (abuse, neglect, exploitation, inappropriate eviction, food quality, medication issues); provision of information on resident rights, provider options, public resources, and regulations; mediation between residents/families and facility staff; regular visits by trained volunteers; education on residents' rights; information and referral services; attendance at resident council meetings[3][4][5]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: State office (602) 542-6454[3][5][6]", "Email: ltcop@azdes.gov[3]", "Mail: Office of Arizona State Long-Term Care Ombudsman Program, 1789 W. Jefferson Street, Mail Drop 6288, Phoenix, Arizona 85007[3][5]", "In-person or regional: Contact local Area Agency on Aging (varies by region, e.g., Area Agency on Aging Region One (520) 432-2528 ext. 206 for Santa Cruz, Cochise, Graham, Greenlee Counties; Inter Tribal Council of Arizona (602) 258-4822 for 21 Tribal Nations; Navajo Nation (602) 542-6454 or (602) 542-6432)[5][6]", "Website: https://des.az.gov/LTCOP[3]"],
    "processing_time": "Not specified; services provided upon contact and consent, with prompt investigation of complaints[4][5]",
    "waitlist": null,
    "forms": ["No specific application forms required; contact ombudsman directly to request assistance[3][5]"],
    "documents": ["Resident consent required for investigation or action; no financial or other documents needed as there are no eligibility tests[3][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Services limited to residents of licensed long-term care facilities; available statewide including tribal areas[3][5]",
    "regional_variations": "Administered regionally through 12 Area Agencies on Aging with local ombudsman offices and volunteers; different contact numbers and providers by region/county/tribal area, but core services consistent statewide[4][5][6]",
    "offices_or_providers": ["State office: Phoenix[3][5]", "Regional examples: Area Agency on Aging Region One (Southern AZ counties), Inter Tribal Council of Arizona (21 Tribal Nations), Navajo Nation Division[5]", "Oversight: DES Division of Aging and Adult Services[5][6]"]
  },
  "official_source": "https://des.az.gov/LTCOP",
  "gotchas": ["Not a financial or direct care program like ALTCS (which has strict income/asset limits and provides long-term care services); this is purely advocacy for resolving facility issues[1][2][3]", "Requires resident consent before acting on complaints; ombudsman prioritizes resident's direction[3][5]", "For abuse/neglect/exploitation, may refer to Adult Protective Services (877-767-2385) in addition to or instead of handling directly[4][6]", "Contact local Area Agency on Aging first for fastest regional response, not just state office[6]", "Free and confidential, but does not provide medical care, housing, or financial aid[3][5]"],
  "data_shape_notes": "no income test; advocacy-only for long-term care facility residents; regionally administered via Area Agencies on Aging with volunteer advocates; consent-driven; often confused with ALTCS long-term care benefits program"
}

{
  "name": "Arizona Pension Income Deduction",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits apply. Available to Arizona taxpayers receiving qualifying pension income, regardless of total income level.",
    "asset_limits": "No asset limits or tests apply.",
    "other_requirements": ["Must file an Arizona individual income tax return (e.g., Form 140).", "Pension must be from qualifying sources: U.S. government service retirement/disability fund, U.S. foreign service retirement/disability system, Arizona state/local government pensions, or other federal retirement systems (excluding uniformed services pay, which has separate 100% subtraction).", "Taxpayer (or spouse, if filing jointly) must have received the pension income during the tax year."]
  },
  "benefits": {
    "type": "financial",
    "value": "Subtraction from Arizona gross income of up to $2,500 per qualifying individual (amount received or $2,500, whichever is less). If both spouses qualify, each may claim up to $2,500 (total up to $5,000). For uniformed services retired/retainer pay, 100% subtraction (unlimited amount) starting tax year 2021. Note: Increases to $5,000 single/head of household and $10,000 married filing jointly after December 31, 2025 per ARS 43-1022.",
    "varies_by": "filing_status"
  },
  "application": {
    "methods": ["Included directly on Arizona individual income tax return (e.g., Form 140 or Form 140PY).", "File electronically or by mail with Arizona Department of Revenue.", "Phone assistance: Arizona Department of Revenue at (602) 255-3381.", "In-person: Arizona Department of Revenue offices (e.g., Phoenix headquarters)."],
    "processing_time": "Processed as part of annual income tax return; standard tax refund timeline (typically 4-6 weeks for e-file, longer for paper).",
    "waitlist": null,
    "forms": ["Arizona Form 140 (Resident Personal Income Tax Return)", "Arizona Form 140PY (Part-Year Resident), or other individual forms as applicable.", "Claim subtraction on Schedule A or directly per form instructions."],
    "documents": ["1099-R or equivalent pension statements showing qualifying income.", "Federal tax return (Form 1040).", "Proof of Arizona residency if part-year filer."]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": null,
    "offices_or_providers": null
  },
  "official_source": "https://azdor.gov/forms/individual-income-tax-forms (Form 140 instructions); https://www.azleg.gov/ars/43/01022.htm",
  "gotchas": ["Limited to $2,500 per person (lesser of amount received or cap); excess pension income remains taxable at Arizona's 2.5% flat rate.", "Only specific government pensions qualify—not private pensions, IRAs, or 401(k)s.", "Must itemize or claim correctly on AZ tax forms; no separate application.", "Uniformed services have unlimited subtraction, often missed.", "If filing separately, subtraction can be split but total capped.", "Non-residents may still owe on AZ-source pensions; consult AZ DOR.", "Changes post-2025: doubles to $5k/$10k."],
  "data_shape_notes": "Tax subtraction claimed annually on state income tax return; no separate program application, no age/income/asset tests, caps per person with post-2025 increases; distinguishes government pensions from private retirement income."
}
